import serial, time
ports=['/dev/cu.usbmodem101','/dev/cu.debug-console']

def open_ports():
    serials=[]
    for port in ports:
        try:
            ser=serial.Serial(port,115200,timeout=0.01)
            serials.append((port,ser))
        except Exception as exc:
            print(f'failed {port}: {exc}')
    return serials

def capture(name, dtr, rts_steps):
    print(f'=== sequence {name} ===')
    serials=open_ports()
    main=dict(serials).get('/dev/cu.usbmodem101')
    for _, ser in serials:
        ser.reset_input_buffer()
    if main:
        main.dtr=dtr
        time.sleep(0.1)
        for rts, delay in rts_steps:
            main.rts=rts
            time.sleep(delay)
    buffers={port:b'' for port,_ in serials}
    end=time.time()+4
    while time.time()<end:
        for port, ser in serials:
            data=ser.read(4096)
            if data:
                buffers[port]+=data
        time.sleep(0.01)
    for port, data in buffers.items():
        text=data.decode('utf-8','replace')
        print(f'--- {port} ---')
        print(text if text.strip() else '<no output>')
    for _, ser in serials:
        ser.close()
    time.sleep(0.4)

capture('DTR_TRUE_RTS_FALSE_THEN_TRUE', True, [(False,0.25),(True,0.25)])
